import ts from"typescript";import{getDefaultImportName,getImportMap,getPropertyValues}from"../../typescript/ast-helpers.js";export const getComponentPathsFromSourceFile=t=>{const e=new Set,s=getImportMap(t),o=getDefaultImportName(s,"@astrojs/starlight");return function t(s){if(ts.isCallExpression(s)&&ts.isIdentifier(s.expression)&&s.expression.text===o){const t=s.arguments[0];if(ts.isObjectLiteralExpression(t)){const s=getPropertyValues(t,"components");for(const t of s)e.add(t)}}ts.forEachChild(s,t)}(t),e};